#include <bits/stdc++.h>
using namespace std;
int cnt[30];
bool isprime(int n){
	if(n<2)return false;
	for(int i=2;i*i<=n;i++)
		if(n%i==0)return false;
	return true;
}
int main(){
	string s;
	cin>>s;
	for(int i=0;i<s.size();i++)
		cnt[s[i]-'a']++;
	int maxn=0,minn=101;
	for(int i=0;i<26;i++){
		maxn=max(maxn,cnt[i]);
		if(cnt[i])minn=min(minn,cnt[i]);
	}
	if(isprime(maxn-minn))
		cout<<"Lucky Word"<<endl<<maxn-minn;
	else
		cout<<"No Answer"<<endl<<0;
	return 0;
}
